package app

import (
	"bytes"
	"encoding/json"
	"fmt"
	"io"
	"net/http"
	"strings"
	"time"

	"github.com/linfree/open-todo/internal/config"
)

// ParsedTask represents structured task data extracted from natural language input.
type ParsedTask struct {
	Title       string  `json:"title"`
	Description string  `json:"description"`
	Priority    string  `json:"priority"`
	DueDate     *string `json:"dueDate"`
	Reminder    *string `json:"reminder"`
}

// BreakdownResult represents a list of subtasks generated by AI.
type BreakdownResult struct {
	Subtasks []Subtask `json:"subtasks"`
}

// Subtask represents a single subtask in a breakdown.
type Subtask struct {
	Title string `json:"title"`
}

// AIService handles AI-powered task operations using OpenAI-compatible APIs.
type AIService struct {
	cfg *config.AIConfig
}

// NewAIService creates a new AIService with configuration loaded from disk.
func NewAIService() *AIService {
	cfg, err := config.LoadAIConfig()
	if err != nil {
		cfg = config.DefaultAIConfig()
	}
	return &AIService{cfg: cfg}
}

// Status returns whether AI is enabled, configured, and the model name.
func (s *AIService) Status() (enabled bool, configured bool, model string) {
	return s.cfg.Enabled, s.cfg.Enabled && s.cfg.APIKey != "", s.cfg.Model
}

// TestConnection tests the AI API connection by sending a minimal chat request.
func (s *AIService) TestConnection() error {
	if s.cfg.APIKey == "" {
		return fmt.Errorf("APIеҜҶй’ҘжңӘй…ҚзҪ®")
	}

	type msg struct {
		Role    string `json:"role"`
		Content string `json:"content"`
	}
	body, _ := json.Marshal(map[string]interface{}{
		"model": s.cfg.Model,
		"messages": []msg{
			{Role: "user", Content: "ping"},
		},
		"max_tokens": 1,
	})

	url := strings.TrimRight(s.cfg.BaseURL, "/") + "/chat/completions"
	req, err := http.NewRequest("POST", url, bytes.NewReader(body))
	if err != nil {
		return fmt.Errorf("еҲӣе»әиҜ·жұӮеӨұиҙҘ: %w", err)
	}
	req.Header.Set("Content-Type", "application/json")
	req.Header.Set("Authorization", "Bearer "+s.cfg.APIKey)

	client := &http.Client{Timeout: 15 * time.Second}
	resp, err := client.Do(req)
	if err != nil {
		return fmt.Errorf("зҪ‘з»ңиҜ·жұӮеӨұиҙҘ: %w", err)
	}
	defer resp.Body.Close()

	if resp.StatusCode == 401 || resp.StatusCode == 403 {
		return fmt.Errorf("APIеҜҶй’Ҙж— ж•Ҳ (зҠ¶жҖҒз Ғ %d)", resp.StatusCode)
	}
	if resp.StatusCode >= 400 {
		respBody, _ := io.ReadAll(resp.Body)
		return fmt.Errorf("APIиҝ”еӣһй”ҷиҜҜ (зҠ¶жҖҒз Ғ %d): %s", resp.StatusCode, string(respBody))
	}

	return nil
}

// ParseTask parses natural language input into a structured task using AI.
func (s *AIService) ParseTask(input string) (*ParsedTask, error) {
	if !s.cfg.Enabled || s.cfg.APIKey == "" {
		return nil, fmt.Errorf("AIжңҚеҠЎжңӘеҗҜз”ЁжҲ–APIеҜҶй’ҘжңӘй…ҚзҪ®")
	}

	systemPrompt := "дҪ жҳҜдёҖдёӘд»»еҠЎи§ЈжһҗеҠ©жүӢгҖӮз”ЁжҲ·дјҡз”ЁиҮӘз„¶иҜӯиЁҖжҸҸиҝ°дёҖдёӘд»»еҠЎпјҢдҪ йңҖиҰҒжҸҗеҸ–еҮәз»“жһ„еҢ–дҝЎжҒҜпјҢеҸӘиҝ”еӣһJSONгҖӮж јејҸпјҡ{\"title\":\"д»»еҠЎж Үйўҳ\",\"description\":\"д»»еҠЎжҸҸиҝ°\",\"priority\":\"none|low|medium|high\",\"dueDate\":\"ISO8601жҲ–null\",\"reminder\":\"ISO8601жҲ–null\"}гҖӮжіЁж„Ҹж—ҘжңҹиҰҒзӣёеҜ№еҪ“еүҚж—¶й—ҙи®Ўз®—пјҢеҰӮ'жҳҺеӨ©дёӢеҚҲ3зӮ№'еә”и®Ўз®—дёәе®һйҷ…ISO8601ж—¶й—ҙгҖӮ"

	now := time.Now()
	contextMsg := fmt.Sprintf("еҪ“еүҚж—¶й—ҙжҳҜ %sпјҲ%sпјүгҖӮиҜ·ж №жҚ®иҝҷдёӘж—¶й—ҙи®Ўз®—зӣёеҜ№ж—ҘжңҹгҖӮ",
		now.Format("2006-01-02T15:04:05-07:00"),
		now.Format("2006е№ҙ1жңҲ2ж—Ҙ 15:04"))

	userMsg := contextMsg + "\nз”ЁжҲ·иҫ“е…Ҙпјҡ" + input

	result, err := s.chatCompletion(systemPrompt, userMsg)
	if err != nil {
		return nil, err
	}

	// Extract JSON from the response (may contain markdown code blocks)
	jsonStr := extractJSON(result)

	var parsed ParsedTask
	if err := json.Unmarshal([]byte(jsonStr), &parsed); err != nil {
		return nil, fmt.Errorf("и§ЈжһҗAIе“Қеә”еӨұиҙҘ: %w, еҺҹе§Ӣе“Қеә”: %s", err, result)
	}

	return &parsed, nil
}

// BreakdownTask breaks down a task into subtasks using AI.
func (s *AIService) BreakdownTask(taskTitle, taskDescription string) (*BreakdownResult, error) {
	if !s.cfg.Enabled || s.cfg.APIKey == "" {
		return nil, fmt.Errorf("AIжңҚеҠЎжңӘеҗҜз”ЁжҲ–APIеҜҶй’ҘжңӘй…ҚзҪ®")
	}

	systemPrompt := "дҪ жҳҜдёҖдёӘд»»еҠЎжӢҶи§ЈеҠ©жүӢгҖӮз”ЁжҲ·дјҡз»ҷдҪ дёҖдёӘд»»еҠЎж Үйўҳе’ҢжҸҸиҝ°пјҢдҪ йңҖиҰҒе°ҶиҝҷдёӘд»»еҠЎжӢҶи§Јдёә3-5дёӘеӯҗд»»еҠЎгҖӮеҸӘиҝ”еӣһJSONгҖӮж јејҸпјҡ{\"subtasks\":[{\"title\":\"еӯҗд»»еҠЎж Үйўҳ\"}]}"

	userMsg := fmt.Sprintf("д»»еҠЎж Үйўҳпјҡ%s\nд»»еҠЎжҸҸиҝ°пјҡ%s", taskTitle, taskDescription)

	result, err := s.chatCompletion(systemPrompt, userMsg)
	if err != nil {
		return nil, err
	}

	// Extract JSON from the response
	jsonStr := extractJSON(result)

	var br BreakdownResult
	if err := json.Unmarshal([]byte(jsonStr), &br); err != nil {
		return nil, fmt.Errorf("и§ЈжһҗAIе“Қеә”еӨұиҙҘ: %w, еҺҹе§Ӣе“Қеә”: %s", err, result)
	}

	return &br, nil
}

// chatCompletion calls the OpenAI-compatible chat completions API.
func (s *AIService) chatCompletion(systemPrompt, userMessage string) (string, error) {
	type Message struct {
		Role    string `json:"role"`
		Content string `json:"content"`
	}

	type RequestBody struct {
		Model    string    `json:"model"`
		Messages []Message `json:"messages"`
	}

	body := RequestBody{
		Model: s.cfg.Model,
		Messages: []Message{
			{Role: "system", Content: systemPrompt},
			{Role: "user", Content: userMessage},
		},
	}

	jsonBody, err := json.Marshal(body)
	if err != nil {
		return "", fmt.Errorf("еәҸеҲ—еҢ–иҜ·жұӮеӨұиҙҘ: %w", err)
	}

	url := strings.TrimRight(s.cfg.BaseURL, "/") + "/chat/completions"
	req, err := http.NewRequest("POST", url, bytes.NewReader(jsonBody))
	if err != nil {
		return "", fmt.Errorf("еҲӣе»әиҜ·жұӮеӨұиҙҘ: %w", err)
	}

	req.Header.Set("Content-Type", "application/json")
	req.Header.Set("Authorization", "Bearer "+s.cfg.APIKey)

	client := &http.Client{Timeout: 60 * time.Second}
	resp, err := client.Do(req)
	if err != nil {
		return "", fmt.Errorf("APIиҜ·жұӮеӨұиҙҘ: %w", err)
	}
	defer resp.Body.Close()

	respBody, err := io.ReadAll(resp.Body)
	if err != nil {
		return "", fmt.Errorf("иҜ»еҸ–е“Қеә”еӨұиҙҘ: %w", err)
	}

	if resp.StatusCode != 200 {
		return "", fmt.Errorf("APIиҝ”еӣһй”ҷиҜҜ (зҠ¶жҖҒз Ғ %d): %s", resp.StatusCode, string(respBody))
	}

	var chatResp struct {
		Choices []struct {
			Message struct {
				Content string `json:"content"`
			} `json:"message"`
		} `json:"choices"`
		Error *struct {
			Message string `json:"message"`
		} `json:"error"`
	}

	if err := json.Unmarshal(respBody, &chatResp); err != nil {
		return "", fmt.Errorf("и§ЈжһҗAPIе“Қеә”еӨұиҙҘ: %w", err)
	}

	if chatResp.Error != nil {
		return "", fmt.Errorf("APIй”ҷиҜҜ: %s", chatResp.Error.Message)
	}

	if len(chatResp.Choices) == 0 {
		return "", fmt.Errorf("APIиҝ”еӣһз©әе“Қеә”")
	}

	return chatResp.Choices[0].Message.Content, nil
}

// extractJSON extracts JSON content from a string that may contain markdown code blocks.
func extractJSON(s string) string {
	s = strings.TrimSpace(s)

	// Strip text before the first { or [ (e.g., thinking chain output)
	if idx := strings.Index(s, "{"); idx > 0 {
		s = s[idx:]
	}
	// Also handle the case where JSON is preceded by text and then array
	if idx := strings.Index(s, "["); idx > 0 && (strings.Index(s, "{") == -1 || idx < strings.Index(s, "{")) {
		s = s[idx:]
	}

	// Try to extract from markdown code blocks: ```json ... ```
	if strings.HasPrefix(s, "```") {
		s = strings.TrimPrefix(s, "```json")
		s = strings.TrimPrefix(s, "```")
		if idx := strings.LastIndex(s, "```"); idx >= 0 {
			s = s[:idx]
		}
		return strings.TrimSpace(s)
	}

	// If there's trailing text after the last }, strip it
	if lastBrace := strings.LastIndex(s, "}"); lastBrace >= 0 && lastBrace < len(s)-1 {
		s = s[:lastBrace+1]
	}

	return s
}
